const express = require('express');
const { graphqlHTTP } = require('express-graphql');
const {
  GraphQLSchema,
  GraphQLObjectType,
  GraphQLString,
  GraphQLInt,
  GraphQLList,
  GraphQLNonNull,
} = require('graphql');
const { Pool } = require('pg');
const depthLimit = require('graphql-depth-limit');
const { createComplexityLimitRule } = require('graphql-validation-complexity');

const pool = new Pool({
  host: process.env.PG_HOST || 'localhost',
  port: parseInt(process.env.PG_PORT, 10) || 5432,
  database: process.env.PG_DATABASE || 'blog',
  user: process.env.PG_USER || 'postgres',
  password: process.env.PG_PASSWORD || 'postgres',
});

async function initializeDatabase() {
  const client = await pool.connect();
  try {
    await client.query(`
      CREATE TABLE IF NOT EXISTS authors (
        id SERIAL PRIMARY KEY,
        name VARCHAR(255) NOT NULL,
        email VARCHAR(255) UNIQUE NOT NULL
      );
    `);
    await client.query(`
      CREATE TABLE IF NOT EXISTS posts (
        id SERIAL PRIMARY KEY,
        title VARCHAR(255) NOT NULL,
        content TEXT,
        author_id INTEGER REFERENCES authors(id) ON DELETE CASCADE
      );
    `);

    const { rows } = await client.query('SELECT COUNT(*) FROM authors');
    if (parseInt(rows[0].count, 10) === 0) {
      await client.query(`
        INSERT INTO authors (name, email) VALUES
          ('Alice Johnson', 'alice@example.com'),
          ('Bob Smith', 'bob@example.com'),
          ('Carol White', 'carol@example.com');
      `);
      await client.query(`
        INSERT INTO posts (title, content, author_id) VALUES
          ('Introduction to GraphQL', 'GraphQL is a query language for APIs...', 1),
          ('Node.js Best Practices', 'Here are some best practices for Node.js...', 1),
          ('PostgreSQL Tips', 'PostgreSQL is a powerful relational database...', 2),
          ('Express Middleware Guide', 'Middleware functions in Express...', 3),
          ('Understanding REST vs GraphQL', 'Comparing two popular API paradigms...', 2);
      `);
      console.log('Seed data inserted.');
    }
  } finally {
    client.release();
  }
}

const AuthorType = new GraphQLObjectType({
  name: 'Author',
  fields: () => ({
    id: { type: new GraphQLNonNull(GraphQLInt) },
    name: { type: new GraphQLNonNull(GraphQLString) },
    email: { type: new GraphQLNonNull(GraphQLString) },
    posts: {
      type: new GraphQLList(PostType),
      async resolve(parent) {
        const { rows } = await pool.query(
          'SELECT * FROM posts WHERE author_id = $1',
          [parent.id]
        );
        return rows;
      },
    },
  }),
});

const PostType = new GraphQLObjectType({
  name: 'Post',
  fields: () => ({
    id: { type: new GraphQLNonNull(GraphQLInt) },
    title: { type: new GraphQLNonNull(GraphQLString) },
    content: { type: GraphQLString },
    author_id: { type: GraphQLInt },
    author: {
      type: AuthorType,
      async resolve(parent) {
        if (!parent.author_id) return null;
        const { rows } = await pool.query(
          'SELECT * FROM authors WHERE id = $1',
          [parent.author_id]
        );
        return rows[0] || null;
      },
    },
  }),
});

const RootQueryType = new GraphQLObjectType({
  name: 'Query',
  fields: {
    posts: {
      type: new GraphQLList(PostType),
      description: 'Get all posts',
      async resolve() {
        const { rows } = await pool.query('SELECT * FROM posts ORDER BY id');
        return rows;
      },
    },
    post: {
      type: PostType,
      description: 'Get a single post by ID',
      args: {
        id: { type: new GraphQLNonNull(GraphQLInt) },
      },
      async resolve(_, args) {
        const { rows } = await pool.query(
          'SELECT * FROM posts WHERE id = $1',
          [args.id]
        );
        return rows[0] || null;
      },
    },
    authors: {
      type: new GraphQLList(AuthorType),
      description: 'Get all authors',
      async resolve() {
        const { rows } = await pool.query('SELECT * FROM authors ORDER BY id');
        return rows;
      },
    },
    author: {
      type: AuthorType,
      description: 'Get a single author by ID',
      args: {
        id: { type: new GraphQLNonNull(GraphQLInt) },
      },
      async resolve(_, args) {
        const { rows } = await pool.query(
          'SELECT * FROM authors WHERE id = $1',
          [args.id]
        );
        return rows[0] || null;
      },
    },
  },
});

const RootMutationType = new GraphQLObjectType({
  name: 'Mutation',
  fields: {
    createAuthor: {
      type: AuthorType,
      args: {
        name: { type: new GraphQLNonNull(GraphQLString) },
        email: { type: new GraphQLNonNull(GraphQLString) },
      },
      async resolve(_, args) {
        const { rows } = await pool.query(
          'INSERT INTO authors (name, email) VALUES ($1, $2) RETURNING *',
          [args.name, args.email]
        );
        return rows[0];
      },
    },
    createPost: {
      type: PostType,
      args: {
        title: { type: new GraphQLNonNull(GraphQLString) },
        content: { type: GraphQLString },
        author_id: { type: new GraphQLNonNull(GraphQLInt) },
      },
      async resolve(_, args) {
        const authorCheck = await pool.query(
          'SELECT id FROM authors WHERE id = $1',
          [args.author_id]
        );
        if (authorCheck.rows.length === 0) {
          throw new Error(`Author with id ${args.author_id} not found`);
        }
        const { rows } = await pool.query(
          'INSERT INTO posts (title, content, author_id) VALUES ($1, $2, $3) RETURNING *',
          [args.title, args.content || null, args.author_id]
        );
        return rows[0];
      },
    },
  },
});

const schema = new GraphQLSchema({
  query: RootQueryType,
  mutation: RootMutationType,
});

const MAX_QUERY_DEPTH = 5;
const MAX_COMPLEXITY = 1000;

const validationRules = [
  depthLimit(MAX_QUERY_DEPTH),
  createComplexityLimitRule(MAX_COMPLEXITY, {
    onCost: (cost) => {
      console.log(`Query complexity: ${cost}`);
    },
    formatErrorMessage: (cost) =>
      `Query complexity of ${cost} exceeds the maximum allowed complexity of ${MAX_COMPLEXITY}`,
  }),
];

const app = express();

const QUERY_SIZE_LIMIT = '100kb';
app.use(express.json({ limit: QUERY_SIZE_LIMIT }));

app.use((req, res, next) => {
  if (req.body && typeof req.body.query === 'string') {
    const queryLength = req.body.query.length;
    if (queryLength > 2000) {
      return res.status(400).json({
        errors: [{ message: `Query too large: ${queryLength} characters (max 2000)` }],
      });
    }
  }
  next();
});

const isProduction = process.env.NODE_ENV === 'production';

app.use(
  '/graphql',
  graphqlHTTP({
    schema,
    graphiql: !isProduction,
    validationRules,
    customFormatErrorFn: (error) => {
      console.error('GraphQL Error:', error.message);
      return {
        message: error.message,
        locations: error.locations,
        path: error.path,
      };
    },
  })
);

app.get('/health', (req, res) => {
  res.json({ status: 'ok' });
});

const PORT = process.env.PORT || 4000;

initializeDatabase()
  .then(() => {
    app.listen(PORT, () => {
      console.log(`GraphQL API server running at http://localhost:${PORT}/graphql`);
      console.log(`GraphiQL available: ${!isProduction}`);
      console.log(`Security: depth limit=${MAX_QUERY_DEPTH}, complexity limit=${MAX_COMPLEXITY}`);
    });
  })
  .catch((err) => {
    console.error('Failed to initialize database:', err);
    process.exit(1);
  });

process.on('SIGTERM', async () => {
  console.log('Shutting down...');
  await pool.end();
  process.exit(0);
});

module.exports = app;